import { calculateTotals } from "../calculateTotals";

describe("calculateTotals", () => {
  it("debe calcular IVA y total sobre el subtotal", () => {
    expect(calculateTotals({ subtotal: 100000, ivaRate: 0.19 })).toEqual({
      subtotal: 100000,
      iva: 19000,
      total: 119000,
    });
  });

  it("debe retornar total igual al subtotal si el IVA es cero", () => {
    expect(calculateTotals({ subtotal: 100000, ivaRate: 0 })).toEqual({
      subtotal: 100000,
      iva: 0,
      total: 100000,
    });
  });

  it("debe lanzar error si el subtotal es negativo", () => {
    expect(() => calculateTotals({ subtotal: -1, ivaRate: 0.19 })).toThrow(
      "El subtotal no puede ser negativo"
    );
  });
});
